import { ActionCreators as Actions } from '../actions';
import { cardTrackingActions } from '../ducks/cardTracking';
import { Creators as CashbackActions } from '../ducks/cashback';
import { PointsActions } from '../ducks/points';
import { activitiesActions } from '../ducks/recentActivities';
import Store from '../store';
import { cardPlaceStoreCleanup } from '../../newArch/store/utils';

export const cleanFintechCardPlaceReducers = <
  ActionT extends typeof Actions,
  StoreT extends typeof Store,
>(
  actionCreators: ActionT,
  reduxStore: StoreT,
) => {
  if (!actionCreators || !reduxStore) return;

  reduxStore?.dispatch(actionCreators?.invoicesFintechClean?.());
  reduxStore?.dispatch(actionCreators?.invoiceFintechClean?.());
  reduxStore?.dispatch(actionCreators?.homeInvoicesClean?.());
  reduxStore?.dispatch(actionCreators?.productClean?.());
  reduxStore?.dispatch(actionCreators?.cardClean?.());
  reduxStore?.dispatch(actionCreators?.clearAddress?.());
  reduxStore?.dispatch(actionCreators?.invoiceBarcodeClean?.());
  reduxStore?.dispatch(actionCreators?.cleanVirtualCard?.());
  reduxStore?.dispatch(actionCreators?.clearContents?.());
  reduxStore?.dispatch(actionCreators?.partnerBanksClean?.());
  reduxStore?.dispatch(actionCreators?.automaticDebtClean?.());
  reduxStore?.dispatch(CashbackActions.clear());
  reduxStore?.dispatch(PointsActions.clear());
  reduxStore?.dispatch(activitiesActions.clear());
  reduxStore?.dispatch(cardTrackingActions.clean());

  cardPlaceStoreCleanup();
};

export const logout = () => {
  Store.dispatch(Actions?.clearAll());

  cleanFintechCardPlaceReducers(Actions, Store);
};

