import type { StateCreator } from 'zustand';
import type { AdditionalCardActions, AdditionalCardState } from '../models';

export type AdditionalCardSlice = {
  additionalCard: AdditionalCardState;
  additionalCardActions: AdditionalCardActions;
};

const initialAdditionalCard: AdditionalCardState = {
  name: '',
  isLoadingName: false,
  isErrorName: false,
  errorNameMessage: '',
  birthDate: '',
  limit: '',
  isLoading: false,
  isError: false,
  errorMessage: '',
};

export const createAdditionalCardSlice: StateCreator<
  AdditionalCardSlice,
  [],
  [],
  AdditionalCardSlice
> = (set) => ({
  additionalCard: initialAdditionalCard,

  additionalCardActions: {
    setName: (name) =>
      set((state) => ({
        additionalCard: {
          ...state.additionalCard,
          name,
          isLoadingName: false,
          isErrorName: false,
          errorNameMessage: '',
        },
      })),

    setLoadingName: (isLoading) =>
      set((state) => ({
        additionalCard: {
          ...state.additionalCard,
          isLoadingName: isLoading,
          ...(isLoading && {
            isErrorName: false,
            errorNameMessage: '',
          }),
        },
      })),

    setErrorName: (error) =>
      set((state) => ({
        additionalCard: {
          ...state.additionalCard,
          isLoadingName: false,
          isErrorName: true,
          errorNameMessage: error,
        },
      })),

    clearNameError: () =>
      set((state) => ({
        additionalCard: {
          ...state.additionalCard,
          isErrorName: false,
          errorNameMessage: '',
        },
      })),

    setBirthDate: (birthDate) =>
      set((state) => ({
        additionalCard: {
          ...state.additionalCard,
          birthDate,
        },
      })),

    setLimit: (limit) =>
      set((state) => ({
        additionalCard: {
          ...state.additionalCard,
          limit,
        },
      })),

    setLoading: (isLoading) =>
      set((state) => ({
        additionalCard: {
          ...state.additionalCard,
          isLoading,
        },
      })),

    setError: (error) =>
      set((state) => ({
        additionalCard: {
          ...state.additionalCard,
          isLoading: false,
          isError: true,
          errorMessage: error,
        },
      })),

    clearError: () =>
      set((state) => ({
        additionalCard: {
          ...state.additionalCard,
          isError: false,
          errorMessage: '',
        },
      })),

    reset: () =>
      set({
        additionalCard: initialAdditionalCard,
      }),
  },
});

