import AsyncStorage from '@react-native-community/async-storage';
import { createStore, compose, applyMiddleware } from 'redux';
import { persistStore, persistCombineReducers } from 'redux-persist';
import createSagaMiddleware from 'redux-saga';
import Reactotron from '~/settings/ReactotronConfig';
import rootReducers from '../reducers/index';
import sagas from '../sagas/index';

const IS_TEST_ENVIRONMENT =
  process.env.NODE_ENV === 'test' || process.env.JEST_WORKER_ID;

const config = {
  key: 'root',
  storage: AsyncStorage,
  blacklist: [
    'securityReducer',
    'cashbackReducer',
    'pointsReducer',
    'consultProtocolReducer',
    'bankReducer',
    'loadingReducer',
    'invoicesReducer',
    'onlinePayment',
    'invoicePreReducer',
    'ticketReducer',
    'pciReducer',
    'zapayReducer',
    'refuelLimitsReducer',
    'sppayReducer',
    'pixReducer',
    'isRefuelReducer',
    'encontreReducer',
    'quizReducer',
    'likeEncontreReducer',
    'geoCodeReducer',
    'typePaymentReducer',
    'sessionReducer',
    'serviceModalReducer',
    'valetReducer',
  ],
  debug: true,
};

const middleware = [];
const sagaMiddleware = createSagaMiddleware();
middleware.push(sagaMiddleware);

const composer =
  __DEV__ && !IS_TEST_ENVIRONMENT
    ? compose(applyMiddleware(...middleware), Reactotron.createEnhancer())
    : compose(applyMiddleware(...middleware));

const reducers = persistCombineReducers(config, rootReducers);
const persistConfig = { composer };
const store = createStore(reducers, composer);

const persistor = persistStore(store, persistConfig);
export const configureStore = () => {
  return { persistor, store };
};

sagaMiddleware.run(sagas);

export default store;

