import { PermissionDocument } from '../../../../src/services/invoiceCashbackPermission/models';
import { invoiceCashbackPermissionRepository } from '../../../../src/services/invoiceCashbackPermission/repository';
import { invoiceCashbackPermissionService } from '../../../../src/services/invoiceCashbackPermission/services';

jest.mock('../../../../src/services/invoiceCashbackPermission/repository');

describe('InvoiceCashbackPermissionService', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('hasRedeemed', () => {
    it('should return true if redeemedAtDate is present', async () => {
      (invoiceCashbackPermissionRepository.getPermission as jest.Mock).mockResolvedValue({
        invoiceCashbackRedemption: {
          redeemedAtDate: '2023-10-27T10:00:00Z',
        },
      });

      const result = await invoiceCashbackPermissionService.hasRedeemed('123');
      expect(result).toBe(true);
    });

    it('should return false if invoiceCashbackRedemption is missing', async () => {
      (invoiceCashbackPermissionRepository.getPermission as jest.Mock).mockResolvedValue({});

      const result = await invoiceCashbackPermissionService.hasRedeemed('123');
      expect(result).toBe(false);
    });

    it('should return false if redeemedAtDate is missing', async () => {
      (invoiceCashbackPermissionRepository.getPermission as jest.Mock).mockResolvedValue({
        invoiceCashbackRedemption: {},
      });

      const result = await invoiceCashbackPermissionService.hasRedeemed('123');
      expect(result).toBe(false);
    });

    it('should return false if repository returns null', async () => {
      (invoiceCashbackPermissionRepository.getPermission as jest.Mock).mockResolvedValue(null);

      const result = await invoiceCashbackPermissionService.hasRedeemed('123');
      expect(result).toBe(false);
    });
  });

  describe('markAsRedeemed', () => {
    it('should call savePermission with correct document', async () => {
      const accountId = '123';
      const expectedDocument: PermissionDocument = {
        codigoCliente: accountId,
        status: 1,
        value: {
          invoiceCashbackRedemption: {
            redeemedAtDate: expect.any(String),
          },
        },
      };

      await invoiceCashbackPermissionService.markAsRedeemed(accountId);

      expect(invoiceCashbackPermissionRepository.savePermission).toHaveBeenCalledWith(
        expectedDocument
      );
    });
  });
});

